#!/bin/bash
/snap/bin/glab orbit local sql "WITH RECURSIVE path_trace AS ( SELECT f.path AS source_file, d.file_path AS target_file, 1 AS depth FROM gl_file f JOIN gl_edge e1 ON f.id = e1.source_id JOIN gl_imported_symbol sym ON e1.target_id = sym.id JOIN gl_edge e2 ON sym.id = e2.source_id JOIN gl_definition d ON e2.target_id = d.id JOIN _orbit_manifest m ON f.project_id = m.project_id WHERE e1.relationship_kind = 'IMPORTS' AND e2.relationship_kind = 'IMPORTS' AND f.path = 'frontend/ui.ts' AND m.repo_path = '/mnt/c/Users/astle/Hackathon/orbit-experiment' UNION ALL SELECT pt.source_file, d2.file_path AS target_file, pt.depth + 1 FROM path_trace pt JOIN gl_file f2 ON pt.target_file = f2.path JOIN gl_edge e3 ON f2.id = e3.source_id JOIN gl_imported_symbol sym2 ON e3.target_id = sym2.id JOIN gl_edge e4 ON sym2.id = e4.source_id JOIN gl_definition d2 ON e4.target_id = d2.id JOIN _orbit_manifest m2 ON f2.project_id = m2.project_id WHERE e3.relationship_kind = 'IMPORTS' AND e4.relationship_kind = 'IMPORTS' AND m2.repo_path = '/mnt/c/Users/astle/Hackathon/orbit-experiment' ) SELECT * FROM path_trace;"
